module.exports = function handler(req, res) {
  res.setHeader('Content-Type', 'text/html; charset=utf-8');
  res.setHeader('Cache-Control', 'no-store');
  const html = "<!DOCTYPE html>\n<html lang=\"ko\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>\uc26c\uc6b4\uccad\uc57d \uc5b4\ub4dc\ubbfc</title>\n<style>\n  * { margin:0; padding:0; box-sizing:border-box; }\n  body { font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif; background:#F1F5F9; color:#1E293B; min-height:100vh; }\n\n  /* \ub85c\uadf8\uc778 */\n  .login-wrap { display:flex; align-items:center; justify-content:center; min-height:100vh; padding:20px; }\n  .login-card { background:#fff; border-radius:20px; padding:40px; width:100%; max-width:400px; box-shadow:0 4px 24px rgba(0,0,0,.08); }\n  .login-logo { text-align:center; margin-bottom:32px; }\n  .login-logo h1 { font-size:24px; font-weight:900; color:#2563EB; }\n  .login-logo p { font-size:13px; color:#94A3B8; margin-top:4px; }\n  .login-inp { width:100%; padding:14px 16px; border:1.5px solid #E2E8F0; border-radius:12px; font-size:15px; outline:none; transition:.2s; }\n  .login-inp:focus { border-color:#2563EB; box-shadow:0 0 0 3px rgba(37,99,235,.1); }\n  .login-btn { width:100%; padding:15px; background:#2563EB; color:#fff; border:none; border-radius:12px; font-size:16px; font-weight:700; cursor:pointer; margin-top:12px; transition:.15s; }\n  .login-btn:hover { background:#1D4ED8; }\n  .login-err { color:#EF4444; font-size:13px; text-align:center; margin-top:8px; display:none; }\n\n  /* \ub808\uc774\uc544\uc6c3 */\n  .app { display:none; }\n  .sidebar { position:fixed; top:0; left:0; width:220px; height:100vh; background:#1E293B; padding:24px 16px; display:flex; flex-direction:column; gap:4px; z-index:100; }\n  .sidebar-logo { font-size:18px; font-weight:900; color:#fff; padding:8px 12px 20px; border-bottom:1px solid rgba(255,255,255,.1); margin-bottom:8px; }\n  .sidebar-logo span { color:#60A5FA; }\n  .nav-item { padding:11px 14px; border-radius:10px; color:rgba(255,255,255,.6); font-size:14px; font-weight:500; cursor:pointer; display:flex; align-items:center; gap:10px; transition:.15s; }\n  .nav-item:hover { background:rgba(255,255,255,.08); color:#fff; }\n  .nav-item.active { background:#2563EB; color:#fff; }\n  .nav-item svg { width:16px; height:16px; flex-shrink:0; }\n  .main { margin-left:220px; padding:20px 24px; min-height:100vh; }\n\n  /* \ubaa8\ubc14\uc77c */\n  @media(max-width:768px) {\n    .sidebar { width:100%; height:auto; position:relative; flex-direction:row; flex-wrap:wrap; padding:12px; gap:4px; }\n    .sidebar-logo { width:100%; padding:4px 8px 12px; margin-bottom:4px; }\n    .nav-item { font-size:12px; padding:8px 10px; }\n    .main { margin-left:0; padding:16px; }\n  }\n\n  /* \ud398\uc774\uc9c0 */\n  .page { display:none; }\n  .page.active { display:block; }\n  .page-title { font-size:22px; font-weight:800; color:#1E293B; margin-bottom:4px; }\n  .page-sub { font-size:13px; color:#94A3B8; margin-bottom:16px; }\n\n  /* \uce74\ub4dc */\n  .card { background:#fff; border-radius:16px; border:1px solid #E2E8F0; padding:24px; margin-bottom:16px; }\n  .card-title { font-size:15px; font-weight:700; color:#1E293B; margin-bottom:16px; display:flex; align-items:center; gap:8px; }\n\n  /* \ud1b5\uacc4 */\n  .stat-grid { display:grid; grid-template-columns:repeat(auto-fit,minmax(140px,1fr)); gap:12px; margin-bottom:24px; }\n  .stat-card { background:#fff; border-radius:14px; border:1px solid #E2E8F0; padding:20px; text-align:center; }\n  .stat-val { font-size:28px; font-weight:900; color:#2563EB; }\n  .stat-label { font-size:12px; color:#94A3B8; margin-top:4px; }\n\n  /* \ud14c\uc774\ube14 */\n  .tbl-wrap { overflow-x:auto; }\n  table { width:100%; border-collapse:collapse; font-size:14px; }\n  th { text-align:left; padding:10px 14px; font-size:12px; font-weight:700; color:#64748B; border-bottom:2px solid #E2E8F0; white-space:nowrap; }\n  td { padding:12px 14px; border-bottom:1px solid #F1F5F9; vertical-align:top; }\n  tr:hover td { background:#F8FAFC; }\n  .badge { display:inline-block; padding:3px 10px; border-radius:20px; font-size:11px; font-weight:700; }\n  .badge-pending { background:#FEF3C7; color:#D97706; }\n  .badge-answered { background:#DCFCE7; color:#16A34A; }\n  .badge-hot { background:#FEE2E2; color:#DC2626; }\n\n  /* \ubc84\ud2bc */\n  .btn { padding:9px 18px; border-radius:10px; font-size:13px; font-weight:700; cursor:pointer; border:none; transition:.15s; }\n  .btn-primary { background:#2563EB; color:#fff; }\n  .btn-primary:hover { background:#1D4ED8; }\n  .btn-danger { background:#FEE2E2; color:#DC2626; }\n  .btn-danger:hover { background:#FECACA; }\n  .btn-sm { padding:6px 12px; font-size:12px; }\n\n  /* \ud3fc */\n  .form-group { margin-bottom:16px; }\n  .form-label { font-size:13px; font-weight:600; color:#475569; margin-bottom:6px; display:block; }\n  .form-inp { width:100%; padding:11px 14px; border:1.5px solid #E2E8F0; border-radius:10px; font-size:14px; outline:none; transition:.2s; font-family:inherit; }\n  .form-inp:focus { border-color:#2563EB; }\n  textarea.form-inp { resize:vertical; min-height:100px; }\n\n  /* \ubb38\uc758 \uc0c1\uc138 */\n  .inquiry-detail { background:#F8FAFC; border-radius:12px; padding:16px; margin-bottom:16px; font-size:14px; line-height:1.7; color:#334155; white-space:pre-wrap; }\n  .modal-ov { display:none; position:fixed; inset:0; background:rgba(0,0,0,.5); z-index:200; align-items:center; justify-content:center; padding:20px; }\n  .modal-ov.show { display:flex; }\n  .modal { background:#fff; border-radius:20px; padding:28px; width:100%; max-width:560px; max-height:90vh; overflow-y:auto; }\n  .modal-title { font-size:18px; font-weight:800; margin-bottom:20px; }\n\n  /* \uacf5\uc9c0\uc0ac\ud56d */\n  .notice-item { display:flex; align-items:flex-start; justify-content:space-between; gap:12px; padding:14px 0; border-bottom:1px solid #F1F5F9; }\n  .notice-item:last-child { border-bottom:none; }\n  .notice-meta { font-size:12px; color:#94A3B8; margin-top:4px; }\n\n  .empty { text-align:center; padding:40px; color:#94A3B8; font-size:14px; }\n  .loading { text-align:center; padding:20px; color:#94A3B8; }\n  .tag-new { background:#DBEAFE; color:#1D4ED8; font-size:10px; font-weight:800; padding:2px 7px; border-radius:20px; margin-left:6px; }\n</style>\n</head>\n<body>\n\n<!-- \ub85c\uadf8\uc778 -->\n<div class=\"login-wrap\" id=\"login-wrap\">\n  <div class=\"login-card\">\n    <div class=\"login-logo\">\n      <h1>\uc26c\uc6b4\uccad\uc57d</h1>\n      <p>\uad00\ub9ac\uc790 \ud398\uc774\uc9c0</p>\n    </div>\n    <input type=\"password\" class=\"login-inp\" id=\"pw-inp\" placeholder=\"\ube44\ubc00\ubc88\ud638 \uc785\ub825\" onkeydown=\"if(event.key==='Enter')doLogin()\">\n    <button class=\"login-btn\" onclick=\"doLogin()\">\ub85c\uadf8\uc778</button>\n    <div class=\"login-err\" id=\"login-err\">\ube44\ubc00\ubc88\ud638\uac00 \ud2c0\ub838\uc5b4\uc694</div>\n  </div>\n</div>\n\n<!-- \uc5b4\ub4dc\ubbfc \uc571 -->\n<div class=\"app\" id=\"app\">\n  <!-- \uc0ac\uc774\ub4dc\ubc14 -->\n  <div class=\"sidebar\">\n    <div class=\"sidebar-logo\">\uc26c\uc6b4<span>\uccad\uc57d</span> \uc5b4\ub4dc\ubbfc</div>\n    <div class=\"nav-item active\" onclick=\"showPage('dashboard')\" id=\"nav-dashboard\">\n      <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><rect x=\"3\" y=\"3\" width=\"7\" height=\"7\"/><rect x=\"14\" y=\"3\" width=\"7\" height=\"7\"/><rect x=\"3\" y=\"14\" width=\"7\" height=\"7\"/><rect x=\"14\" y=\"14\" width=\"7\" height=\"7\"/></svg>\n      \ub300\uc2dc\ubcf4\ub4dc\n    </div>\n    <div class=\"nav-item\" onclick=\"showPage('inquiries')\" id=\"nav-inquiries\">\n      <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z\"/></svg>\n      \ubb38\uc758 \uad00\ub9ac\n      <span id=\"pending-badge\" style=\"background:#EF4444;color:#fff;font-size:10px;font-weight:800;padding:2px 6px;border-radius:20px;margin-left:auto;display:none\"></span>\n    </div>\n    <div class=\"nav-item\" onclick=\"showPage('notices')\" id=\"nav-notices\">\n      <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7\"/><path d=\"M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z\"/></svg>\n      \uacf5\uc9c0\uc0ac\ud56d\n    </div>\n    <div class=\"nav-item\" onclick=\"showPage('users')\" id=\"nav-users\">\n      <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2\"/><circle cx=\"9\" cy=\"7\" r=\"4\"/><path d=\"M23 21v-2a4 4 0 0 0-3-3.87\"/><path d=\"M16 3.13a4 4 0 0 1 0 7.75\"/></svg>\n      \uc720\uc800 \ud604\ud669\n    </div>\n    <div class=\"nav-item\" onclick=\"showPage('pdf')\" id=\"nav-pdf\">\n      <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z\"/><polyline points=\"14 2 14 8 20 8\"/><line x1=\"16\" y1=\"13\" x2=\"8\" y2=\"13\"/><line x1=\"16\" y1=\"17\" x2=\"8\" y2=\"17\"/></svg>\n      \uacf5\uace0 PDF \ub4f1\ub85d\n    </div>\n    <div class=\"nav-item\" onclick=\"showPage('listings')\" id=\"nav-listings\">\n      <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M9 5H7a2 2 0 0 0-2 2v12a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2V7a2 2 0 0 0-2-2h-2\"/><rect x=\"9\" y=\"3\" width=\"6\" height=\"4\" rx=\"1\"/><line x1=\"9\" y1=\"12\" x2=\"15\" y2=\"12\"/><line x1=\"9\" y1=\"16\" x2=\"13\" y2=\"16\"/></svg>\n      \uacf5\uace0 \uad00\ub9ac\n    </div>\n    <div style=\"margin-top:auto;padding-top:16px;border-top:1px solid rgba(255,255,255,.1)\">\n      <div class=\"nav-item\" onclick=\"doLogout()\" style=\"color:rgba(255,255,255,.4)\">\n        <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4\"/><polyline points=\"16 17 21 12 16 7\"/><line x1=\"21\" y1=\"12\" x2=\"9\" y2=\"12\"/></svg>\n        \ub85c\uadf8\uc544\uc6c3\n      </div>\n    </div>\n  </div>\n\n  <div class=\"main\">\n    <!-- \ub300\uc2dc\ubcf4\ub4dc -->\n    <div class=\"page active\" id=\"page-dashboard\">\n      <div class=\"page-title\">\ub300\uc2dc\ubcf4\ub4dc</div>\n      <div class=\"page-sub\">\uc26c\uc6b4\uccad\uc57d \uc11c\ube44\uc2a4 \ud604\ud669</div>\n      <div class=\"stat-grid\" id=\"stat-grid\">\n        <div class=\"stat-card\"><div class=\"stat-val\" id=\"stat-users\">-</div><div class=\"stat-label\">\uc804\uccb4 \uc720\uc800</div></div>\n        <div class=\"stat-card\"><div class=\"stat-val\" id=\"stat-tokens\">-</div><div class=\"stat-label\">\ud478\uc2dc \ud1a0\ud070</div></div>\n        <div class=\"stat-card\"><div class=\"stat-val\" id=\"stat-inquiries\">-</div><div class=\"stat-label\">\uc804\uccb4 \ubb38\uc758</div></div>\n        <div class=\"stat-card\"><div class=\"stat-val\" id=\"stat-pending\">-</div><div class=\"stat-label\">\ubbf8\ub2f5\ubcc0 \ubb38\uc758</div></div>\n      </div>\n      <div class=\"card\">\n        <div class=\"card-title\">\ud83d\udccb \ucd5c\uadfc \ubb38\uc758</div>\n        <div id=\"recent-inquiries\"><div class=\"loading\">\ubd88\ub7ec\uc624\ub294 \uc911...</div></div>\n      </div>\n    </div>\n\n    <!-- \ubb38\uc758 \uad00\ub9ac -->\n    <div class=\"page\" id=\"page-inquiries\">\n      <div class=\"page-title\">\ubb38\uc758 \uad00\ub9ac</div>\n      <div class=\"page-sub\">\uc720\uc800 \ubb38\uc758 \ubaa9\ub85d \ubc0f \ub2f5\ubcc0</div>\n      <div class=\"card\">\n        <div class=\"tbl-wrap\">\n          <table>\n            <thead>\n              <tr>\n                <th>\uc0c1\ud0dc</th>\n                <th>\ub2c9\ub124\uc784</th>\n                <th>\uc81c\ubaa9</th>\n                <th>\uc811\uc218\uc77c</th>\n                <th>\uad00\ub9ac</th>\n              </tr>\n            </thead>\n            <tbody id=\"inquiries-tbody\"><tr><td colspan=\"5\" class=\"loading\">\ubd88\ub7ec\uc624\ub294 \uc911...</td></tr></tbody>\n          </table>\n        </div>\n      </div>\n    </div>\n\n    <!-- \uacf5\uc9c0\uc0ac\ud56d -->\n    <div class=\"page\" id=\"page-notices\">\n      <div class=\"page-title\">\uacf5\uc9c0\uc0ac\ud56d</div>\n      <div class=\"page-sub\">\uc571 \ub0b4 \uacf5\uc9c0\uc0ac\ud56d \uad00\ub9ac</div>\n      <div class=\"card\">\n        <div class=\"card-title\">\u270f\ufe0f \uc0c8 \uacf5\uc9c0 \uc791\uc131</div>\n        <div class=\"form-group\">\n          <label class=\"form-label\">\uc81c\ubaa9</label>\n          <input type=\"text\" class=\"form-inp\" id=\"notice-title\" placeholder=\"\uacf5\uc9c0 \uc81c\ubaa9\uc744 \uc785\ub825\ud558\uc138\uc694\">\n        </div>\n        <div class=\"form-group\">\n          <label class=\"form-label\">\ub0b4\uc6a9</label>\n          <textarea class=\"form-inp\" id=\"notice-content\" placeholder=\"\uacf5\uc9c0 \ub0b4\uc6a9\uc744 \uc785\ub825\ud558\uc138\uc694\" style=\"min-height:120px\"></textarea>\n        </div>\n        <div style=\"display:flex;align-items:center;gap:12px\">\n          <label style=\"display:flex;align-items:center;gap:6px;font-size:13px;font-weight:600;color:#475569;cursor:pointer\">\n            <input type=\"checkbox\" id=\"notice-hot\"> \ud83d\udd25 \uc911\uc694 \uacf5\uc9c0 (NEW \ubc30\uc9c0)\n          </label>\n          <button class=\"btn btn-primary\" onclick=\"addNotice()\" style=\"margin-left:auto\">\uacf5\uc9c0 \ub4f1\ub85d</button>\n        </div>\n      </div>\n      <div class=\"card\">\n        <div class=\"card-title\">\ud83d\udce2 \ub4f1\ub85d\ub41c \uacf5\uc9c0</div>\n        <div id=\"notices-list\"><div class=\"loading\">\ubd88\ub7ec\uc624\ub294 \uc911...</div></div>\n      </div>\n    </div>\n\n    <!-- \uc720\uc800 \ud604\ud669 -->\n    <div class=\"page\" id=\"page-users\">\n      <div class=\"page-title\">\uc720\uc800 \ud604\ud669</div>\n      <div class=\"page-sub\">\uac00\uc785 \uc720\uc800 \ubc0f \ud478\uc2dc \ud1a0\ud070 \ud604\ud669</div>\n      <div class=\"card\">\n        <div class=\"tbl-wrap\">\n          <table>\n            <thead>\n              <tr>\n                <th>\ub2c9\ub124\uc784</th>\n                <th>\uc544\uc774\ub514</th>\n                <th>\ub85c\uadf8\uc778</th>\n                <th>\uac00\uc785\uc77c</th>\n              </tr>\n            </thead>\n            <tbody id=\"users-tbody\"><tr><td colspan=\"4\" class=\"loading\">\ubd88\ub7ec\uc624\ub294 \uc911...</td></tr></tbody>\n          </table>\n        </div>\n      </div>\n    </div>\n\n    <!-- \uacf5\uace0 PDF \ub4f1\ub85d -->\n    <div class=\"page\" id=\"page-pdf\">\n      <div class=\"page-title\">\uacf5\uace0 PDF \ub4f1\ub85d</div>\n      <div class=\"page-sub\">\uccad\uc57d \uacf5\uace0\ubb38 PDF\ub97c \uc5c5\ub85c\ub4dc\ud558\uba74 AI\uac00 \uc790\ub3d9\uc73c\ub85c \ub370\uc774\ud130\ub97c \ucd94\ucd9c\ud574\uc694</div>\n\n      <div class=\"card\">\n        <div class=\"card-title\">\ud83d\udcc4 PDF \uc5c5\ub85c\ub4dc</div>\n\n        <!-- \ub4dc\ub86d\uc874 -->\n        <div id=\"pdf-drop\" onclick=\"document.getElementById('pdf-file-input').click()\"\n          style=\"border:2px dashed #BFDBFE;border-radius:16px;padding:40px 20px;text-align:center;cursor:pointer;background:#EFF6FF;transition:.2s;margin-bottom:16px\">\n          <div style=\"font-size:40px;margin-bottom:12px\">\ud83d\udcc4</div>\n          <div style=\"font-size:16px;font-weight:700;color:#2563EB\">\uacf5\uace0\ubb38 PDF \uc5c5\ub85c\ub4dc</div>\n          <div style=\"font-size:13px;color:#93C5FD;margin-top:6px\">\ud074\ub9ad\ud574\uc11c \ud30c\uc77c \uc120\ud0dd (\ucd5c\ub300 5MB)</div>\n        </div>\n        <input type=\"file\" id=\"pdf-file-input\" accept=\".pdf\" style=\"display:none\" onchange=\"onPdfSelect(event)\">\n\n        <!-- \uc0c1\ud0dc -->\n        <div id=\"pdf-status\" style=\"display:none;padding:14px 16px;border-radius:12px;font-size:14px;font-weight:600;margin-bottom:16px\"></div>\n\n        <!-- \ubbf8\ub9ac\ubcf4\uae30 -->\n        <div id=\"pdf-preview\" style=\"display:none\">\n          <div style=\"font-size:15px;font-weight:800;color:#1E293B;margin-bottom:12px\">\ud83d\udccb \ucd94\ucd9c\ub41c \ub370\uc774\ud130 \ud655\uc778</div>\n          <div id=\"pdf-preview-body\" style=\"background:#F8FAFC;border-radius:12px;padding:16px;font-size:14px;line-height:1.8;margin-bottom:16px\"></div>\n          <div id=\"pdf-price-warn\" style=\"display:none;background:#FEF3C7;border:1px solid #FCD34D;border-radius:10px;padding:12px 14px;font-size:13px;color:#92400E;margin-bottom:16px\"></div>\n          <div style=\"display:flex;gap:10px\">\n            <button class=\"btn btn-primary\" onclick=\"confirmPdf()\" style=\"flex:1;padding:14px\">\u2713 \uacf5\uace0 \ub4f1\ub85d\ud558\uae30</button>\n            <button class=\"btn\" onclick=\"resetPdf()\" style=\"background:#F1F5F9;color:#64748B;padding:14px 20px\">\ub2e4\uc2dc</button>\n          </div>\n        </div>\n      </div>\n\n      <!-- \ub4f1\ub85d\ub41c \uacf5\uace0 \ubaa9\ub85d -->\n      <div class=\"card\">\n        <div class=\"card-title\">\ud83d\udccb \ub4f1\ub85d\ub41c \uacf5\uace0 <span id=\"pdf-listing-count\" style=\"color:#2563EB\">0</span>\uac74</div>\n        <div id=\"pdf-listing-list\"><div class=\"loading\">\ubd88\ub7ec\uc624\ub294 \uc911...</div></div>\n      </div>\n    </div>\n  </div>\n</div>\n\n    <!-- \uacf5\uace0 \uad00\ub9ac -->\n    <div class=\"page\" id=\"page-listings\">\n      <div class=\"page-title\" style=\"margin-bottom:2px;font-size:18px\">\uacf5\uace0 \uad00\ub9ac</div>\n      <div class=\"page-sub\" style=\"margin-bottom:12px\">\ud604\uc7ac \ub4f1\ub85d\ub41c \uc804\uccb4 \uacf5\uace0 \u00b7 \uc218\uc815 \ubc0f \uc0ad\uc81c</div>\n      <div class=\"card\" style=\"padding:16px\">\n        <div style=\"display:flex;gap:8px;margin-bottom:12px;flex-wrap:wrap\">\n          <input type=\"text\" class=\"form-inp\" id=\"listing-search\" placeholder=\"\uacf5\uace0\uba85, \uc9c0\uc5ed \uac80\uc0c9...\" oninput=\"filterListings()\" style=\"flex:1;min-width:120px;padding:8px 12px\">\n          <select class=\"form-inp\" id=\"listing-type-filter\" onchange=\"filterListings()\" style=\"width:90px;padding:8px 12px\">\n            <option value=\"\">\uc804\uccb4</option>\n            <option value=\"public\">\uacf5\uacf5</option>\n            <option value=\"private\">\ubbfc\uac04</option>\n          </select>\n        </div>\n        <div id=\"listings-count\" style=\"font-size:12px;color:#94A3B8;margin-bottom:8px\"></div>\n        <div id=\"listings-table\" style=\"overflow-x:auto\"><div class=\"loading\">\ubd88\ub7ec\uc624\ub294 \uc911...</div></div>\n      </div>\n    </div>\n\n  </div><!-- /main -->\n\n  <!-- \ubb38\uc758 \ub2f5\ubcc0 \ubaa8\ub2ec -->\n<div class=\"modal-ov\" id=\"inquiry-modal\">\n  <div class=\"modal\">\n    <div class=\"modal-title\" id=\"modal-title\">\ubb38\uc758 \ub2f5\ubcc0</div>\n    <div style=\"margin-bottom:12px\">\n      <div style=\"font-size:12px;font-weight:700;color:#94A3B8;margin-bottom:6px\">\ubb38\uc758 \ub0b4\uc6a9</div>\n      <div class=\"inquiry-detail\" id=\"modal-content\"></div>\n    </div>\n    <div class=\"form-group\">\n      <label class=\"form-label\">\ub2f5\ubcc0 \uc791\uc131</label>\n      <textarea class=\"form-inp\" id=\"modal-answer\" placeholder=\"\ub2f5\ubcc0\uc744 \uc785\ub825\ud558\uc138\uc694\" style=\"min-height:140px\"></textarea>\n    </div>\n    <div style=\"display:flex;gap:10px;justify-content:flex-end\">\n      <button class=\"btn\" onclick=\"closeModal()\" style=\"background:#F1F5F9;color:#64748B\">\ucde8\uc18c</button>\n      <button class=\"btn btn-primary\" onclick=\"submitAnswer()\">\ub2f5\ubcc0 \ub4f1\ub85d</button>\n    </div>\n  </div>\n</div>\n\n<!-- \uacf5\uace0 \uc218\uc815 \ubaa8\ub2ec -->\n<div class=\"modal-ov\" id=\"listing-modal\">\n  <div class=\"modal\" style=\"max-width:680px\">\n    <div class=\"modal-title\">\uacf5\uace0 \uc218\uc815</div>\n    <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:12px\">\n      <div class=\"form-group\" style=\"grid-column:1/-1\">\n        <label class=\"form-label\">\ub2e8\uc9c0\uba85 *</label>\n        <input type=\"text\" class=\"form-inp\" id=\"edit-name\">\n      </div>\n      <div class=\"form-group\" style=\"grid-column:1/-1\">\n        <label class=\"form-label\">\uc704\uce58 *</label>\n        <input type=\"text\" class=\"form-inp\" id=\"edit-loc\">\n      </div>\n      <div class=\"form-group\">\n        <label class=\"form-label\">\ubd84\uc591\uac00 (\ud45c\uc2dc\uc6a9)</label>\n        <input type=\"text\" class=\"form-inp\" id=\"edit-price\" placeholder=\"\uc608: 59\u33a1 5\uc5b52\ucc9c\">\n      </div>\n      <div class=\"form-group\">\n        <label class=\"form-label\">\ucd5c\uc800 \ubd84\uc591\uac00 (\ub9cc\uc6d0)</label>\n        <input type=\"number\" class=\"form-inp\" id=\"edit-minp\">\n      </div>\n      <div class=\"form-group\">\n        <label class=\"form-label\">\uc811\uc218 \uc2dc\uc791\uc77c</label>\n        <input type=\"date\" class=\"form-inp\" id=\"edit-as\">\n      </div>\n      <div class=\"form-group\">\n        <label class=\"form-label\">\uc811\uc218 \uc885\ub8cc\uc77c (\ub9c8\uac10)</label>\n        <input type=\"date\" class=\"form-inp\" id=\"edit-ae\">\n      </div>\n      <div class=\"form-group\">\n        <label class=\"form-label\">\ub2f9\ucca8\uc790 \ubc1c\ud45c\uc77c</label>\n        <input type=\"date\" class=\"form-inp\" id=\"edit-ad\">\n      </div>\n      <div class=\"form-group\">\n        <label class=\"form-label\">\ucd1d \uc138\ub300\uc218</label>\n        <input type=\"number\" class=\"form-inp\" id=\"edit-units\">\n      </div>\n      <div class=\"form-group\" style=\"grid-column:1/-1\">\n        <label class=\"form-label\">\uacf5\uae09 \uba74\uc801</label>\n        <input type=\"text\" class=\"form-inp\" id=\"edit-size\" placeholder=\"\uc608: 59\u33a1 / 84\u33a1\">\n      </div>\n      <div class=\"form-group\" style=\"grid-column:1/-1\">\n        <label class=\"form-label\">\uc2e0\uccad \uc790\uaca9</label>\n        <textarea class=\"form-inp\" id=\"edit-qual\" style=\"min-height:70px\"></textarea>\n      </div>\n      <div class=\"form-group\" style=\"grid-column:1/-1\">\n        <label class=\"form-label\">\uc18c\ub4dd \uae30\uc900</label>\n        <input type=\"text\" class=\"form-inp\" id=\"edit-inc\">\n      </div>\n      <div class=\"form-group\" style=\"grid-column:1/-1\">\n        <label class=\"form-label\">\uacf5\uae09 \uc804\ud615 (\uc27c\ud45c\ub85c \uad6c\ubd84)</label>\n        <input type=\"text\" class=\"form-inp\" id=\"edit-elig\" placeholder=\"\uc608: \uc2e0\ud63c\ubd80\ubd80\ud2b9\uacf5, \uc0dd\uc560\ucd5c\ucd08, \uc77c\ubc18\uacf5\uae09\">\n      </div>\n      <div class=\"form-group\">\n        <label class=\"form-label\">\ubd84\uc591 \ud0c0\uc785</label>\n        <select class=\"form-inp\" id=\"edit-type\">\n          <option value=\"public\">\uacf5\uacf5</option>\n          <option value=\"private\">\ubbfc\uac04</option>\n        </select>\n      </div>\n      <div class=\"form-group\">\n        <label class=\"form-label\">\uc9c0\uc5ed</label>\n        <select class=\"form-inp\" id=\"edit-region\">\n          <option value=\"seoul\">\uc11c\uc6b8</option>\n          <option value=\"gyeonggi\">\uacbd\uae30</option>\n          <option value=\"incheon\">\uc778\ucc9c</option>\n          <option value=\"busan\">\ubd80\uc0b0</option>\n          <option value=\"daejeon\">\ub300\uc804</option>\n          <option value=\"sejong\">\uc138\uc885</option>\n          <option value=\"daegu\">\ub300\uad6c</option>\n          <option value=\"gwangju\">\uad11\uc8fc</option>\n          <option value=\"ulsan\">\uc6b8\uc0b0</option>\n          <option value=\"gangwon\">\uac15\uc6d0</option>\n          <option value=\"chungnam\">\ucda9\ub0a8</option>\n          <option value=\"jeonnam\">\uc804\ub0a8</option>\n        </select>\n      </div>\n    </div>\n    <div style=\"display:flex;gap:10px;justify-content:flex-end;margin-top:16px\">\n      <button class=\"btn\" onclick=\"closeListingModal()\" style=\"background:#F1F5F9;color:#64748B\">\ucde8\uc18c</button>\n      <button class=\"btn btn-danger\" onclick=\"deleteCurrentListing()\">\ud83d\uddd1 \uc0ad\uc81c</button>\n      <button class=\"btn btn-primary\" onclick=\"saveListingEdit()\">\uc800\uc7a5</button>\n    </div>\n  </div>\n</div>\n</div><!-- /app -->\n\n<script>\nconst SUPABASE_URL = 'https://jmgdljcbbdyttfvmfvzx.supabase.co';\nconst SUPABASE_ANON = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImptZ2RsamNiYmR5dHRmdm1mdnp4Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3Mzk3NTA3NSwiZXhwIjoyMDg5NTUxMDc1fQ.bw0ImAIlzWvfEPHPfQrW17SNBmmeCsIkJlp850vsN3w';\nconst ADMIN_PW = 'dhwlddj12@';\n\nlet currentInquiryId = null;\n\n// \u2500\u2500 Supabase \ud5ec\ud37c \u2500\u2500\nasync function sb(method, path, body) {\n  const res = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, {\n    method,\n    headers: {\n      'apikey': SUPABASE_ANON,\n      'Authorization': `Bearer ${SUPABASE_ANON}`,\n      'Content-Type': 'application/json',\n      'Prefer': method === 'POST' ? 'return=representation' : ''\n    },\n    body: body ? JSON.stringify(body) : undefined\n  });\n  if (!res.ok && res.status !== 204) return null;\n  if (res.status === 204) return true;\n  return res.json();\n}\n\n// \u2500\u2500 \ub85c\uadf8\uc778 \u2500\u2500\nfunction doLogin() {\n  const pw = document.getElementById('pw-inp').value;\n  if (pw === ADMIN_PW) {\n    sessionStorage.setItem('admin_auth', '1');\n    document.getElementById('login-wrap').style.display = 'none';\n    document.getElementById('app').style.display = 'block';\n    loadAll();\n  } else {\n    document.getElementById('login-err').style.display = 'block';\n  }\n}\nfunction doLogout() {\n  sessionStorage.removeItem('admin_auth');\n  location.reload();\n}\n\n// \uc790\ub3d9 \ub85c\uadf8\uc778 \uccb4\ud06c\nif (sessionStorage.getItem('admin_auth') === '1') {\n  document.getElementById('login-wrap').style.display = 'none';\n  document.getElementById('app').style.display = 'block';\n  window.addEventListener('DOMContentLoaded', loadAll);\n}\n\n// \u2500\u2500 \ud398\uc774\uc9c0 \uc804\ud658 \u2500\u2500\nfunction showPage(name) {\n  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));\n  document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));\n  document.getElementById('page-' + name).classList.add('active');\n  document.getElementById('nav-' + name).classList.add('active');\n  if (name === 'inquiries') loadInquiries();\n  if (name === 'notices') loadNotices();\n  if (name === 'users') loadUsers();\n  if (name === 'dashboard') loadDashboard();\n  if (name === 'pdf') loadPdfListings();\n  if (name === 'listings') loadListings();\n}\n\n// \u2500\u2500 \uc804\uccb4 \ub85c\ub4dc \u2500\u2500\nasync function loadAll() {\n  loadDashboard();\n}\n\n// \u2500\u2500 \ub300\uc2dc\ubcf4\ub4dc \u2500\u2500\nasync function loadDashboard() {\n  const [profiles, tokens, inquiries] = await Promise.all([\n    sb('GET', 'profiles?select=id'),\n    sb('GET', 'push_tokens?select=id'),\n    sb('GET', 'inquiries?select=id,status,nickname,title,created_at&order=created_at.desc&limit=5'),\n  ]);\n\n  document.getElementById('stat-users').textContent = profiles?.length ?? '-';\n  document.getElementById('stat-tokens').textContent = tokens?.length ?? '-';\n\n  const all = await sb('GET', 'inquiries?select=id,status');\n  const pending = all?.filter(i => i.status === 'pending') ?? [];\n  document.getElementById('stat-inquiries').textContent = all?.length ?? '-';\n  document.getElementById('stat-pending').textContent = pending.length;\n\n  // \ubbf8\ub2f5\ubcc0 \ubc43\uc9c0\n  if (pending.length > 0) {\n    const badge = document.getElementById('pending-badge');\n    badge.textContent = pending.length;\n    badge.style.display = 'inline-block';\n  }\n\n  // \ucd5c\uadfc \ubb38\uc758\n  const tbody = document.getElementById('recent-inquiries');\n  if (!inquiries?.length) { tbody.innerHTML = '<div class=\"empty\">\ubb38\uc758\uac00 \uc5c6\uc5b4\uc694</div>'; return; }\n  tbody.innerHTML = `<table style=\"width:100%;border-collapse:collapse;font-size:14px\">\n    <thead><tr>\n      <th style=\"text-align:left;padding:8px 12px;font-size:12px;color:#94A3B8;border-bottom:2px solid #E2E8F0\">\uc0c1\ud0dc</th>\n      <th style=\"text-align:left;padding:8px 12px;font-size:12px;color:#94A3B8;border-bottom:2px solid #E2E8F0\">\ub2c9\ub124\uc784</th>\n      <th style=\"text-align:left;padding:8px 12px;font-size:12px;color:#94A3B8;border-bottom:2px solid #E2E8F0\">\uc81c\ubaa9</th>\n    </tr></thead>\n    <tbody>${inquiries.map(i => `<tr onclick=\"showPage('inquiries')\" style=\"cursor:pointer\">\n      <td style=\"padding:10px 12px;border-bottom:1px solid #F1F5F9\"><span class=\"badge badge-${i.status === 'pending' ? 'pending' : 'answered'}\">${i.status === 'pending' ? '\ubbf8\ub2f5\ubcc0' : '\ub2f5\ubcc0\uc644\ub8cc'}</span></td>\n      <td style=\"padding:10px 12px;border-bottom:1px solid #F1F5F9;font-weight:600\">${i.nickname || '-'}</td>\n      <td style=\"padding:10px 12px;border-bottom:1px solid #F1F5F9;color:#64748B\">${i.title || '-'}</td>\n    </tr>`).join('')}</tbody>\n  </table>`;\n}\n\n// \u2500\u2500 \ubb38\uc758 \ubaa9\ub85d \u2500\u2500\nasync function loadInquiries() {\n  document.getElementById('inquiries-tbody').innerHTML = '<tr><td colspan=\"5\" class=\"loading\">\ubd88\ub7ec\uc624\ub294 \uc911...</td></tr>';\n  const data = await sb('GET', 'inquiries?select=*&order=created_at.desc');\n  if (!data?.length) {\n    document.getElementById('inquiries-tbody').innerHTML = '<tr><td colspan=\"5\" class=\"empty\">\ubb38\uc758\uac00 \uc5c6\uc5b4\uc694</td></tr>';\n    return;\n  }\n  document.getElementById('inquiries-tbody').innerHTML = data.map(i => `\n    <tr>\n      <td><span class=\"badge badge-${i.status === 'pending' ? 'pending' : 'answered'}\">${i.status === 'pending' ? '\ubbf8\ub2f5\ubcc0' : '\ub2f5\ubcc0\uc644\ub8cc'}</span></td>\n      <td style=\"font-weight:600\">${i.nickname || '-'}</td>\n      <td style=\"max-width:240px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap\">${i.title || '-'}</td>\n      <td style=\"color:#94A3B8;font-size:12px;white-space:nowrap\">${new Date(i.created_at).toLocaleDateString('ko-KR')}</td>\n      <td><button class=\"btn btn-primary btn-sm\" onclick=\"openInquiry(${i.id})\">\ub2f5\ubcc0\ud558\uae30</button></td>\n    </tr>\n  `).join('');\n}\n\n// \u2500\u2500 \ubb38\uc758 \ub2f5\ubcc0 \ubaa8\ub2ec \u2500\u2500\nasync function openInquiry(id) {\n  currentInquiryId = id;\n  const data = await sb('GET', `inquiries?id=eq.${id}&select=*`);\n  if (!data?.[0]) return;\n  const item = data[0];\n  document.getElementById('modal-title').textContent = item.title || '\ubb38\uc758 \ub0b4\uc6a9';\n  document.getElementById('modal-content').textContent = item.content || '';\n  document.getElementById('modal-answer').value = item.answer || '';\n  document.getElementById('inquiry-modal').classList.add('show');\n}\nfunction closeModal() {\n  document.getElementById('inquiry-modal').classList.remove('show');\n  currentInquiryId = null;\n}\nasync function submitAnswer() {\n  const answer = document.getElementById('modal-answer').value.trim();\n  if (!answer) { alert('\ub2f5\ubcc0\uc744 \uc785\ub825\ud574\uc8fc\uc138\uc694'); return; }\n  // \ub2f5\ubcc0 \uc800\uc7a5 \uc804 \ubb38\uc758 \uc815\ubcf4 \uc870\ud68c\n  const inquiryData = await sb('GET', `inquiries?id=eq.${currentInquiryId}&select=nickname,title`);\n  const nickname = inquiryData?.[0]?.nickname;\n  const title = inquiryData?.[0]?.title;\n  await sb('PATCH', `inquiries?id=eq.${currentInquiryId}`, {\n    answer,\n    status: 'answered',\n    answered_at: new Date().toISOString()\n  });\n  // \ud478\uc2dc \uc54c\ub9bc \ubc1c\uc1a1\n  if (nickname) {\n    fetch('/api/notify-answer', {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({ nickname, title })\n    }).catch(e => console.error('\ud478\uc2dc \uc2e4\ud328:', e));\n  }\n  closeModal();\n  loadInquiries();\n  alert('\ub2f5\ubcc0\uc774 \ub4f1\ub85d\ub410\uc5b4\uc694!');\n}\n\n// \u2500\u2500 \uacf5\uc9c0\uc0ac\ud56d \u2500\u2500\nasync function loadNotices() {\n  const data = await sb('GET', 'notices?select=*&order=created_at.desc');\n  const el = document.getElementById('notices-list');\n  if (!data?.length) { el.innerHTML = '<div class=\"empty\">\ub4f1\ub85d\ub41c \uacf5\uc9c0\uac00 \uc5c6\uc5b4\uc694</div>'; return; }\n  el.innerHTML = data.map(n => `\n    <div class=\"notice-item\">\n      <div style=\"flex:1\">\n        <div style=\"font-size:15px;font-weight:700;color:#1E293B\">\n          ${n.is_hot ? '<span class=\"badge badge-hot\" style=\"margin-right:6px\">HOT</span>' : ''}\n          ${n.title}\n        </div>\n        <div class=\"notice-meta\">${new Date(n.created_at).toLocaleDateString('ko-KR')}</div>\n        ${n.content ? `<div style=\"font-size:13px;color:#64748B;margin-top:6px;line-height:1.6\">${n.content}</div>` : ''}\n      </div>\n      <button class=\"btn btn-danger btn-sm\" onclick=\"deleteNotice(${n.id})\">\uc0ad\uc81c</button>\n    </div>\n  `).join('');\n}\nasync function addNotice() {\n  const title = document.getElementById('notice-title').value.trim();\n  const content = document.getElementById('notice-content').value.trim();\n  const is_hot = document.getElementById('notice-hot').checked;\n  if (!title) { alert('\uc81c\ubaa9\uc744 \uc785\ub825\ud574\uc8fc\uc138\uc694'); return; }\n  await sb('POST', 'notices', { title, content, is_hot });\n  document.getElementById('notice-title').value = '';\n  document.getElementById('notice-content').value = '';\n  document.getElementById('notice-hot').checked = false;\n  loadNotices();\n  alert('\uacf5\uc9c0\uac00 \ub4f1\ub85d\ub410\uc5b4\uc694!');\n}\nasync function deleteNotice(id) {\n  if (!confirm('\uc0ad\uc81c\ud560\uae4c\uc694?')) return;\n  await sb('DELETE', `notices?id=eq.${id}`);\n  loadNotices();\n}\n\n// \u2500\u2500 \uc720\uc800 \ud604\ud669 \u2500\u2500\nasync function loadUsers() {\n  const data = await sb('GET', 'profiles?select=id,kakao_id,nickname,avatar,created_at&order=created_at.desc');\n  if (!data?.length) {\n    document.getElementById('users-tbody').innerHTML = '<tr><td colspan=\"4\" class=\"empty\">\uc720\uc800\uac00 \uc5c6\uc5b4\uc694</td></tr>';\n    return;\n  }\n  document.getElementById('users-tbody').innerHTML = data.map(u => `\n    <tr>\n      <td style=\"font-weight:600\">${u.nickname || '-'}</td>\n      <td style=\"font-size:12px;color:#94A3B8\">${u.kakao_id || u.id || '-'}</td>\n      <td style=\"font-size:12px;color:#94A3B8\">${u.id?.startsWith('naver_') ? '<span style=\"background:#DCFCE7;color:#16A34A;padding:3px 8px;border-radius:20px;font-size:11px;font-weight:700\">\ub124\uc774\ubc84</span>' : '<span style=\"background:#FEF9C3;color:#CA8A04;padding:3px 8px;border-radius:20px;font-size:11px;font-weight:700\">\uce74\uce74\uc624</span>'}</td>\n      <td style=\"color:#94A3B8;font-size:12px\">${u.created_at ? new Date(u.created_at).toLocaleDateString('ko-KR') : '-'}</td>\n    </tr>\n  `).join('');\n}\n\n// \u2500\u2500 PDF \uc5c5\ub85c\ub4dc \u2500\u2500\nlet _pdfExtracted = null;\n\nfunction resetPdf() {\n  _pdfExtracted = null;\n  document.getElementById('pdf-status').style.display = 'none';\n  document.getElementById('pdf-preview').style.display = 'none';\n  document.getElementById('pdf-drop').style.display = 'block';\n  document.getElementById('pdf-file-input').value = '';\n}\n\nasync function onPdfSelect(event) {\n  const file = event.target.files[0];\n  if (!file) return;\n\n  document.getElementById('pdf-drop').style.display = 'none';\n  const statusEl = document.getElementById('pdf-status');\n  statusEl.style.display = 'block';\n  statusEl.style.background = '#FFF8EC';\n  statusEl.style.border = '1px solid rgba(245,166,35,.3)';\n  statusEl.style.color = '#92400E';\n  statusEl.textContent = '\ud83d\udcc4 ' + file.name + ' \uc77d\ub294 \uc911... AI\uac00 \ubd84\uc11d\ud558\uace0 \uc788\uc5b4\uc694';\n\n  if (file.size > 5 * 1024 * 1024) {\n    statusEl.style.background = '#FEE2E2'; statusEl.style.color = '#DC2626';\n    statusEl.textContent = '\u274c \ud30c\uc77c\uc774 \ub108\ubb34 \ucee4\uc694 (\ucd5c\ub300 5MB)';\n    document.getElementById('pdf-drop').style.display = 'block';\n    return;\n  }\n\n  try {\n    const base64 = await new Promise((res, rej) => {\n      const reader = new FileReader();\n      reader.onload = () => res(reader.result.split(',')[1]);\n      reader.onerror = () => rej(new Error('\ud30c\uc77c \uc77d\uae30 \uc2e4\ud328'));\n      reader.readAsDataURL(file);\n    });\n\n    const prompt = `\ub2e4\uc74c \uccad\uc57d \uacf5\uace0\ubb38 PDF\ub97c \ubd84\uc11d\ud574\uc11c JSON \ud615\uc2dd\uc73c\ub85c\ub9cc \uc751\ub2f5\ud574\uc918. \ub9c8\ud06c\ub2e4\uc6b4 \ucf54\ub4dc\ube14\ub85d \uc5c6\uc774 \uc21c\uc218 JSON\ub9cc.\n\n{\n  \"name\": \"\ub2e8\uc9c0\uba85\",\n  \"pblancNo\": \"\uacf5\uace0\ubc88\ud638. \uc5c6\uc73c\uba74 \ube48 \ubb38\uc790\uc5f4\",\n  \"builder\": \"\uc2dc\uacf5\uc0ac\uba85. \uc5c6\uc73c\uba74 \ube48 \ubb38\uc790\uc5f4\",\n  \"loc\": \"\uacf5\uae09\uc704\uce58 \uc8fc\uc18c (\ubc88\uc9c0\uae4c\uc9c0 \ud3ec\ud568)\",\n  \"region\": \"\uc9c0\uc5ed\ucf54\ub4dc (seoul/gyeonggi/incheon/busan/daejeon/sejong/daegu/gwangju/ulsan/gangwon/chungnam/jeonnam \uc911 \ud558\ub098)\",\n  \"type\": \"public \ub610\ub294 private\",\n  \"priceRaw\": \"\uacf5\uae09\uae08\uc561\ud45c '\uacc4' \uceec\ub7fc \uc6d0\ubcf8. \ud615\uc2dd: \ud0c0\uc785\uba85:\uc6d0\ubcf8\uc22b\uc790\ub2e8\uc704|\ud0c0\uc785\uba85:\uc6d0\ubcf8\uc22b\uc790\ub2e8\uc704\",\n  \"minP\": \"\ucd5c\uc800 \ubd84\uc591\uac00(\ub9cc\uc6d0, \uc815\uc218)\",\n  \"mktP\": 0,\n  \"deadline\": \"\uccad\uc57d \ub9c8\uac10\uc77c YYYY-MM-DD. \uc5c6\uc73c\uba74 9999-12-31\",\n  \"size\": \"\uacf5\uae09 \uba74\uc801 (\uc608: 59\u33a1 / 84\u33a1)\",\n  \"units\": \"\ucd1d \uc138\ub300\uc218(\uc815\uc218)\",\n  \"recruitUnits\": \"\ubaa8\uc9d1 \uc138\ub300\uc218(\uc815\uc218)\",\n  \"qual\": \"\uc2e0\uccad \uc790\uaca9 \ud575\uc2ec \uc694\uc57d\",\n  \"inc\": \"\uc18c\ub4dd \uae30\uc900 \uc694\uc57d\",\n  \"sched\": \"\uc811\uc218: YYYY-MM-DD ~ YYYY-MM-DD / \ubc1c\ud45c: YYYY-MM-DD\",\n  \"aS\": \"\uc811\uc218 \uc2dc\uc791\uc77c YYYY-MM-DD\",\n  \"aE\": \"\uc811\uc218 \uc885\ub8cc\uc77c YYYY-MM-DD\",\n  \"aD\": \"\ub2f9\ucca8\uc790 \ubc1c\ud45c\uc77c YYYY-MM-DD\",\n  \"elig\": [\"\uacf5\uae09\uc720\ud615 \ubc30\uc5f4: \uc0dd\uc560\ucd5c\ucd08/\uc2e0\uc0dd\uc544\ud2b9\uacf5/\ub2e4\uc790\ub140\ud2b9\uacf5/\uccad\ub144\ud2b9\uacf5/\uc2e0\ud63c\ubd80\ubd80\ud2b9\uacf5/\ub178\ubd80\ubaa8\ubd80\uc591/\uc77c\ubc18\uacf5\uae09/\ubb34\uc21c\uc704(\uc90d\uc90d)\"],\n  \"downPct\": \"\uacc4\uc57d\uae08 \ube44\uc728(%). \uc5c6\uc73c\uba74 10\",\n  \"comp\": \"\uc608\uc0c1 \uacbd\uc7c1\ub960. \uc5c6\uc73c\uba74 10\",\n  \"localPriorityRatio\": \"\ub2f9\ud574\uc9c0\uc5ed \uc6b0\uc120\ubc30\uc815 \ube44\uc728(%). \uc5c6\uc73c\uba74 100\"\n}`;\n\n    const response = await fetch('https://chengyak-proxy.vercel.app/api/claude', {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({\n        model: 'claude-haiku-4-5-20251001',\n        max_tokens: 4096,\n        messages: [{\n          role: 'user',\n          content: [\n            { type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: base64 } },\n            { type: 'text', text: prompt }\n          ]\n        }]\n      })\n    });\n\n    const data = await response.json();\n    if (!response.ok || !data.content) throw new Error(data.error?.message || '\uc11c\ubc84 \uc624\ub958');\n\n    let text = data.content.map(c => c.text || '').join('');\n    let clean = text.replace(/```json|```/g, '').trim();\n    const s = clean.indexOf('{'), e = clean.lastIndexOf('}');\n    if (s >= 0 && e > s) clean = clean.slice(s, e + 1);\n    clean = clean.replace(/,\\s*([\\]}])/g, '$1');\n    const parsed = JSON.parse(clean);\n\n    // \ubd84\uc591\uac00 \ubcc0\ud658\n    let price = parsed.priceRaw || '';\n    if (price) {\n      try {\n        price = price.split('|').map(seg => {\n          const m = seg.match(/^([^:]+):(.*)/);\n          if (!m) return seg;\n          const typeName = m[1].trim();\n          const nums = m[2].replace(/\uc6d0/g,'').split('~').map(v => {\n            let n = parseInt(v.replace(/,/g,'').trim()) || 0;\n            if (n > 200000) n = Math.round(n / 10000);\n            return n;\n          }).filter(n => n > 0);\n          if (!nums.length) return seg;\n          const fmt = n => n >= 10000 ? `${Math.floor(n/10000)}\uc5b5${n%10000?` ${(n%10000).toLocaleString()}\ub9cc`:''}` : `${n.toLocaleString()}\ub9cc`;\n          return typeName + '\u33a1 ' + nums.map(fmt).join('~');\n        }).join(' | ');\n      } catch(e) {}\n    }\n\n    let minP = parseInt(parsed.minP) || 0;\n    if (minP > 200000) minP = Math.round(minP / 10000);\n\n    _pdfExtracted = {\n      id: Date.now(),\n      name: parsed.name || '',\n      pblancNo: parsed.pblancNo || '',\n      builder: parsed.builder || '',\n      loc: parsed.loc || '',\n      region: parsed.region || '',\n      type: parsed.type || 'private',\n      priceRaw: parsed.priceRaw || '',\n      price,\n      minP,\n      mktP: 0,\n      deadline: parsed.aE || '9999-12-31',\n      size: parsed.size || '',\n      units: parseInt(parsed.units) || 0,\n      recruitUnits: parseInt(parsed.recruitUnits) || 0,\n      qual: parsed.qual || '',\n      inc: parsed.inc || '',\n      sched: parsed.sched || '',\n      aS: parsed.aS || '',\n      aE: parsed.aE || '',\n      aD: parsed.aD || '',\n      elig: parsed.elig || [],\n      eligDetail: [],\n      eligTiers: [],\n      downPct: parsed.downPct || 10,\n      comp: parsed.comp || 10,\n      localPriorityRatio: parsed.localPriorityRatio || 100,\n      lotto: (parsed.elig || []).includes('\ubb34\uc21c\uc704(\uc90d\uc90d)'),\n      days: (() => {\n        if (!parsed.aE || parsed.aE.startsWith('9999')) return null;\n        const d = new Date(parsed.aE);\n        const t = new Date(); t.setHours(0,0,0,0);\n        return Math.ceil((d - t) / 86400000);\n      })(),\n      noMktP: true,\n      priceFactors: [],\n      _src: 'pdf',\n      _updatedAt: new Date().toISOString(),\n    };\n\n    statusEl.style.background = '#DCFCE7'; statusEl.style.color = '#16A34A';\n    statusEl.textContent = '\u2713 \ucd94\ucd9c \uc644\ub8cc! \uc544\ub798 \ub0b4\uc6a9\uc744 \ud655\uc778\ud558\uc138\uc694';\n\n    document.getElementById('pdf-preview-body').innerHTML = [\n      ['\ub2e8\uc9c0\uba85', parsed.name], ['\uc704\uce58', parsed.loc], ['\ubd84\uc591\uac00', price],\n      ['\uc6d0\ubcf8\uae08\uc561', parsed.priceRaw || '-'], ['\uc138\ub300\uc218', `${parsed.units || '?'}\uc138\ub300 (\ubaa8\uc9d1 ${parsed.recruitUnits || '?'}\uc138\ub300)`],\n      ['\ub9c8\uac10\uc77c', parsed.aE], ['\uc804\ud615', (parsed.elig || []).join(', ')], ['\uc18c\ub4dd\uae30\uc900', parsed.inc], ['\uc790\uaca9', parsed.qual],\n    ].map(([k, v]) => `<div style=\"display:flex;gap:10px;padding:6px 0;border-bottom:1px solid #F1F5F9\">\n      <span style=\"font-size:12px;color:#94A3B8;width:70px;flex-shrink:0;padding-top:2px\">${k}</span>\n      <span style=\"font-size:14px;font-weight:600;color:#1E293B;flex:1\">${v || '\u2014'}</span>\n    </div>`).join('');\n\n    document.getElementById('pdf-preview').style.display = 'block';\n\n  } catch(e) {\n    statusEl.style.background = '#FEE2E2'; statusEl.style.color = '#DC2626';\n    statusEl.textContent = '\u274c \ucd94\ucd9c \uc2e4\ud328: ' + e.message;\n    document.getElementById('pdf-drop').style.display = 'block';\n  }\n}\n\nasync function confirmPdf() {\n  if (!_pdfExtracted) return;\n  try {\n    const res = await fetch(LISTINGS_API, {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({ listing: _pdfExtracted })\n    });\n    const data = await res.json();\n    if (data.duplicate) {\n      if (confirm('\uc774\ubbf8 \ub4f1\ub85d\ub41c \uacf5\uace0. \ub36e\uc5b4\uc4f8\uae4c\uc694?')) {\n        const res2 = await fetch(LISTINGS_API, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ listing: _pdfExtracted, force: true }) });\n        if (res2.ok) { alert('\ub36e\uc5b4\uc4f0\uae30 \uc644\ub8cc!'); resetPdf(); loadPdfListings(); }\n      }\n      return;\n    }\n    if (res.ok) { alert('\uacf5\uace0 \ub4f1\ub85d \uc644\ub8cc! \uc571\uc5d0\uc11c \ud655\uc778\ud574\ubcf4\uc138\uc694.'); resetPdf(); loadPdfListings(); }\n    else { alert('\ub4f1\ub85d \uc2e4\ud328. \ub2e4\uc2dc \uc2dc\ub3c4\ud574\uc8fc\uc138\uc694.'); }\n  } catch(e) { alert('\uc624\ub958: ' + e.message); }\n}\n\nasync function loadPdfListings() {\n  const el = document.getElementById('pdf-listing-list');\n  let data = [];\n  try { const r = await fetch(LISTINGS_API); const j = await r.json(); data = (j.listings || []).filter(l => l._src === 'pdf'); } catch(e) {}\n  document.getElementById('pdf-listing-count').textContent = data.length;\n  if (!data.length) { el.innerHTML = '<div class=\'empty\'>\ub4f1\ub85d\ub41c \uacf5\uace0\uac00 \uc5c6\uc5b4\uc694</div>'; return; }\n  el.innerHTML = '<table style=\'width:100%;border-collapse:collapse;font-size:14px\'><thead><tr><th style=\'text-align:left;padding:8px 12px;font-size:12px;color:#94A3B8;border-bottom:2px solid #E2E8F0\'>\ub2e8\uc9c0\uba85</th><th style=\'text-align:left;padding:8px 12px;font-size:12px;color:#94A3B8;border-bottom:2px solid #E2E8F0\'>\uc704\uce58</th><th style=\'text-align:left;padding:8px 12px;font-size:12px;color:#94A3B8;border-bottom:2px solid #E2E8F0\'>\ub9c8\uac10\uc77c</th><th></th></tr></thead><tbody>' + data.map(l => '<tr><td style=\'padding:10px 12px;border-bottom:1px solid #F1F5F9;font-weight:600\'>' + l.name + '</td><td style=\'padding:10px 12px;border-bottom:1px solid #F1F5F9;color:#64748B;font-size:13px\'>' + (l.loc||'-') + '</td><td style=\'padding:10px 12px;border-bottom:1px solid #F1F5F9;color:#94A3B8;font-size:12px\'>' + (l.deadline||'-') + '</td><td style=\'padding:10px 12px;border-bottom:1px solid #F1F5F9\'><button class=\'btn btn-danger btn-sm\' onclick=\'deletePdfListing(' + l.id + ')\'>\uc0ad\uc81c</button></td></tr>').join('') + '</tbody></table>';\n}\n\nasync function deletePdfListing(id) {\n  if (!confirm('\uc0ad\uc81c\ud560\uae4c\uc694?')) return;\n  await fetch(`${LISTINGS_API}?id=${id}`, { method: 'DELETE' });\n  loadPdfListings();\n}\n\n// \u2500\u2500 \uacf5\uace0 \uad00\ub9ac \u2500\u2500\nconst LISTINGS_API = 'https://chengyak-proxy.vercel.app/api/listings';\nlet _allListings = [];\nlet _currentEditId = null;\n\nasync function loadListings() {\n  document.getElementById('listings-table').innerHTML = '<div class=\"loading\">\ubd88\ub7ec\uc624\ub294 \uc911...</div>';\n  try {\n    const res = await fetch(LISTINGS_API);\n    const data = await res.json();\n    _allListings = data.listings || [];\n    renderListingsTable(_allListings);\n  } catch(e) {\n    document.getElementById('listings-table').innerHTML = '<div class=\"empty\">\ubd88\ub7ec\uc624\uae30 \uc2e4\ud328</div>';\n  }\n}\n\nfunction filterListings() {\n  const q = document.getElementById('listing-search').value.toLowerCase();\n  const type = document.getElementById('listing-type-filter').value;\n  const filtered = _allListings.filter(l => {\n    const matchQ = !q || (l.name||'').toLowerCase().includes(q) || (l.loc||'').toLowerCase().includes(q);\n    const matchType = !type || l.type === type;\n    return matchQ && matchType;\n  });\n  renderListingsTable(filtered);\n}\n\nfunction renderListingsTable(list) {\n  const countEl = document.getElementById('listings-count');\n  const tableEl = document.getElementById('listings-table');\n  countEl.textContent = `\ucd1d ${list.length}\uac74`;\n  if (!list.length) { tableEl.innerHTML = '<div class=\"empty\">\uacf5\uace0\uac00 \uc5c6\uc5b4\uc694</div>'; return; }\n\n  tableEl.innerHTML = `<div class=\"tbl-wrap\"><table>\n    <thead><tr>\n      <th>\ub2e8\uc9c0\uba85</th>\n      <th>\uc704\uce58</th>\n      <th>\uc804\ud615</th>\n      <th>\ub9c8\uac10</th>\n      <th>\ud0c0\uc785</th>\n      <th>\uad00\ub9ac</th>\n    </tr></thead>\n    <tbody>${list.map(l => {\n      const days = l.days;\n      const daysColor = days <= 3 ? '#DC2626' : days <= 7 ? '#D97706' : '#64748B';\n      const daysText = days === null ? '-' : days < 0 ? '\ub9c8\uac10' : `D-${days}`;\n      return `<tr>\n        <td style=\"font-weight:700;max-width:160px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap\">${l.name || '-'}</td>\n        <td style=\"font-size:12px;color:#64748B;max-width:140px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap\">${l.loc || '-'}</td>\n        <td style=\"font-size:11px;max-width:120px\">${(l.elig||[]).slice(0,2).join(', ')}${(l.elig||[]).length>2?'...':''}</td>\n        <td style=\"font-size:12px;font-weight:700;color:${daysColor};white-space:nowrap\">${daysText}</td>\n        <td><span style=\"background:${l.type==='public'?'#DBEAFE':'#DCFCE7'};color:${l.type==='public'?'#1D4ED8':'#16A34A'};padding:3px 8px;border-radius:20px;font-size:11px;font-weight:700\">${l.type==='public'?'\uacf5\uacf5':'\ubbfc\uac04'}</span></td>\n        <td><button class=\"btn btn-primary btn-sm\" onclick=\"openListingEdit(${l.id})\">\uc218\uc815</button></td>\n      </tr>`;\n    }).join('')}</tbody>\n  </table></div>`;\n}\n\nfunction openListingEdit(id) {\n  const l = _allListings.find(x => x.id == id);\n  if (!l) return;\n  _currentEditId = id;\n  document.getElementById('edit-name').value = l.name || '';\n  document.getElementById('edit-loc').value = l.loc || '';\n  document.getElementById('edit-price').value = l.price || '';\n  document.getElementById('edit-minp').value = l.minP || '';\n  document.getElementById('edit-as').value = l.aS || '';\n  document.getElementById('edit-ae').value = l.aE || '';\n  document.getElementById('edit-ad').value = l.aD || '';\n  document.getElementById('edit-units').value = l.units || '';\n  document.getElementById('edit-size').value = l.size || '';\n  document.getElementById('edit-qual').value = l.qual || '';\n  document.getElementById('edit-inc').value = l.inc || '';\n  document.getElementById('edit-elig').value = (l.elig || []).join(', ');\n  document.getElementById('edit-type').value = l.type || 'private';\n  document.getElementById('edit-region').value = l.region || 'seoul';\n  document.getElementById('listing-modal').classList.add('show');\n}\n\nfunction closeListingModal() {\n  document.getElementById('listing-modal').classList.remove('show');\n  _currentEditId = null;\n}\n\nasync function saveListingEdit() {\n  if (!_currentEditId) return;\n  const eligStr = document.getElementById('edit-elig').value;\n  const elig = eligStr.split(',').map(s => s.trim()).filter(Boolean);\n  const aE = document.getElementById('edit-ae').value;\n\n  // days \uc7ac\uacc4\uc0b0\n  let days = null;\n  if (aE && !aE.startsWith('9999')) {\n    const d = new Date(aE); const t = new Date(); t.setHours(0,0,0,0);\n    days = Math.ceil((d - t) / 86400000);\n  }\n\n  const updated = {\n    id: _currentEditId,\n    name: document.getElementById('edit-name').value,\n    loc: document.getElementById('edit-loc').value,\n    price: document.getElementById('edit-price').value,\n    minP: parseInt(document.getElementById('edit-minp').value) || 0,\n    aS: document.getElementById('edit-as').value,\n    aE,\n    aD: document.getElementById('edit-ad').value,\n    deadline: aE,\n    units: parseInt(document.getElementById('edit-units').value) || 0,\n    size: document.getElementById('edit-size').value,\n    qual: document.getElementById('edit-qual').value,\n    inc: document.getElementById('edit-inc').value,\n    elig,\n    type: document.getElementById('edit-type').value,\n    region: document.getElementById('edit-region').value,\n    days,\n  };\n\n  try {\n    const res = await fetch(LISTINGS_API, {\n      method: 'PUT',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({ listing: updated })\n    });\n    if (res.ok) {\n      closeListingModal();\n      await loadListings();\n      alert('\uc800\uc7a5\ub410\uc5b4\uc694!');\n    } else {\n      alert('\uc800\uc7a5 \uc2e4\ud328. \ub2e4\uc2dc \uc2dc\ub3c4\ud574\uc8fc\uc138\uc694.');\n    }\n  } catch(e) {\n    alert('\uc624\ub958: ' + e.message);\n  }\n}\n\nasync function deleteCurrentListing() {\n  if (!_currentEditId) return;\n  if (!confirm('\uc815\ub9d0 \uc0ad\uc81c\ud560\uae4c\uc694?')) return;\n  try {\n    const res = await fetch(`${LISTINGS_API}?id=${_currentEditId}`, { method: 'DELETE' });\n    if (res.ok) {\n      closeListingModal();\n      await loadListings();\n      alert('\uc0ad\uc81c\ub410\uc5b4\uc694!');\n    } else {\n      alert('\uc0ad\uc81c \uc2e4\ud328.');\n    }\n  } catch(e) {\n    alert('\uc624\ub958: ' + e.message);\n  }\n}\n\n// \ubaa8\ub2ec \uc678\ubd80 \ud074\ub9ad \ub2eb\uae30\ndocument.getElementById('listing-modal')?.addEventListener('click', function(e) {\n  if (e.target === this) closeListingModal();\n});\n\n// \ubaa8\ub2ec \uc678\ubd80 \ud074\ub9ad \ub2eb\uae30\ndocument.getElementById('inquiry-modal').addEventListener('click', function(e) {\n  if (e.target === this) closeModal();\n});\n\n// \uc5d4\ud130\ub85c \ub85c\uadf8\uc778\ndocument.addEventListener('DOMContentLoaded', () => {\n  const inp = document.getElementById('pw-inp');\n  if (inp) inp.focus();\n});\n</script>\n</body>\n</html>\n";
  res.status(200).send(html);
};
